from langchain_core.runnables import RunnableLambda

def route_insufficient(response: ConfidentGroundedResponse):
    if response.confidence >= 0.75:
        return {"status": "ok", "answer": response.answer}
    if response.confidence >= 0.4:
        # Rewrite the query and retry once
        reformulated = query_rewriter.invoke(original_question)
        new_docs = retriever.invoke(reformulated)
        retry = chain.invoke({"context": format_docs(new_docs),
                               "question": reformulated})
        return {"status": "retried", "answer": retry.answer}
    # Confidence too low — refuse
    return {
        "status": "insufficient",
        "message": response.caveat or "Insufficient context to answer.",
    }

# Wire into a runnable
safe_chain = chain | RunnableLambda(route_insufficient)

output = safe_chain.invoke({
    "context": format_docs(docs),
    "question": "What is the maximum memory per pod in the cluster?"
})
print(output)

def format_docs_for_grounding(docs: list, style: str = "numbered") -> str:
    """Format retrieved docs with clear source markers.

    style='numbered'  →  [1] text\n\n[2] text ...
    style='xml'       →  <source id="1">text</source> ...
    style='fence'     →  ```source-1\ntext\n``` ...
    """
    if style == "numbered":
        return "\n\n".join(f"[{i+1}] {d.page_content}" for i, d in enumerate(docs))
    if style == "xml":
        parts = []
        for i, d in enumerate(docs):
            meta = d.metadata.get("source", f"doc-{i+1}")
            parts.append(f'<source id="{i+1}" file="{meta}">\n{d.page_content}\n</source>')
        return "\n\n".join(parts)
    # fence
    return "\n\n".join(
        f"```source-{i+1}\n{d.page_content}\n```" for i, d in enumerate(docs)
    )

# Numbered style works best with citation instructions
context_str = format_docs_for_grounding(docs, style="numbered")
result = chain.invoke({"context": context_str, "question": question})
